package com.example.demo.controller;
import com.example.demo.dto.StatusRequest; import com.example.demo.service.SalesService; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/admin") public class AdminController {private final SalesService service;public AdminController(SalesService service){this.service=service;}@GetMapping("/users") public List<Map<String,Object>> users(@RequestHeader("Authorization")String auth){return service.users(auth);}@PatchMapping("/users/{email}/status") public Map<String,Object> status(@RequestHeader("Authorization")String auth,@PathVariable String email,@RequestBody StatusRequest r){return service.changeUser(auth,email,r);}@GetMapping("/dashboard") public Map<String,Object> dashboard(@RequestHeader("Authorization")String auth){return service.dashboard(auth);}}
